module RefModule(
    input       clk,
    input       reset,
    input       enable,
    output reg [2:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
        q <= 3'b000;
    else if (enable)
        q <= q + 1;
end

endmodule
